import{_ as e,o as t,c as o,a0 as n}from"./chunks/framework.BjpW4enL.js";const p=JSON.parse('{"title":"Relatório Técnico: Fundações Arquiteturais do IntraClinica NG & Plano de Implementação Kanban","description":"","frontmatter":{},"headers":[],"relativePath":"Z_Archive/wiki_legacy/archive/legacy_reports/relatorio-arquitetura-kanban.md","filePath":"Z_Archive/wiki_legacy/archive/legacy_reports/relatorio-arquitetura-kanban.md","lastUpdated":1782593311000}'),r={name:"Z_Archive/wiki_legacy/archive/legacy_reports/relatorio-arquitetura-kanban.md"};function d(i,a,l,s,c,u){return t(),o("div",null,[...a[0]||(a[0]=[n('<h1 id="relatorio-tecnico-fundacoes-arquiteturais-do-intraclinica-ng-plano-de-implementacao-kanban" tabindex="-1">Relatório Técnico: Fundações Arquiteturais do IntraClinica NG &amp; Plano de Implementação Kanban <a class="header-anchor" href="#relatorio-tecnico-fundacoes-arquiteturais-do-intraclinica-ng-plano-de-implementacao-kanban" aria-label="Permalink to &quot;Relatório Técnico: Fundações Arquiteturais do IntraClinica NG &amp; Plano de Implementação Kanban&quot;">​</a></h1><h2 id="_1-visao-geral-do-projeto" tabindex="-1">1. VISÃO GERAL DO PROJETO <a class="header-anchor" href="#_1-visao-geral-do-projeto" aria-label="Permalink to &quot;1. VISÃO GERAL DO PROJETO&quot;">​</a></h2><p><strong>IntraClinica NG</strong> é um SaaS de gestão clínica multi-tenant, construído com <strong>Angular 20+</strong> (zoneless, standalone, Signals) no frontend e <strong>Supabase</strong> (PostgreSQL + RLS + GoTrue) como backend.</p><h3 id="stack-tecnologico" tabindex="-1">Stack tecnológico <a class="header-anchor" href="#stack-tecnologico" aria-label="Permalink to &quot;Stack tecnológico&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Camada</th><th>Tecnologia</th></tr></thead><tbody><tr><td>Frontend</td><td>Angular 20+ standalone, zoneless (<code>provideZonelessChangeDetection</code>)</td></tr><tr><td>State (server)</td><td><code>@tanstack/angular-query-experimental</code> (TanStack Query)</td></tr><tr><td>State (local)</td><td>Angular Signals (<code>signal</code>, <code>computed</code>)</td></tr><tr><td>UI Framework</td><td>Tailwind CSS + custom Helm (spartan/ui) components</td></tr><tr><td>Ícones</td><td>Lucide Angular</td></tr><tr><td>Backend</td><td>Supabase (PostgreSQL + RLS + RPC + Edge Functions)</td></tr><tr><td>Auth</td><td>Supabase GoTrue + IAM próprio baseado em bindings JSON</td></tr><tr><td>Multi-tenancy</td><td><code>clinic_id</code> em todas as tabelas + RLS</td></tr></tbody></table><h2 id="_2-arquitetura-de-modulos-ddd-por-bounded-contexts" tabindex="-1">2. ARQUITETURA DE MÓDULOS (DDD por Bounded Contexts) <a class="header-anchor" href="#_2-arquitetura-de-modulos-ddd-por-bounded-contexts" aria-label="Permalink to &quot;2. ARQUITETURA DE MÓDULOS (DDD por Bounded Contexts)&quot;">​</a></h2><p>O projeto segue uma <strong>Arquitetura Modular Plugável</strong> com <strong>Domain-Driven Design</strong> (DDD).</p><h3 id="_2-3-padroes-de-codigo-descobertos" tabindex="-1">2.3. Padrões de Código Descobertos <a class="header-anchor" href="#_2-3-padroes-de-codigo-descobertos" aria-label="Permalink to &quot;2.3. Padrões de Código Descobertos&quot;">​</a></h3><ul><li><strong>Domain Models</strong>: puramente TypeScript com interfaces, sem dependências Angular.</li><li><strong>Domain Rules</strong>: Funções puras em <code>domain/rules/</code>.</li><li><strong>Services (Application Layer)</strong>: Usam <code>injectQuery</code> e <code>injectMutation</code> do <strong>TanStack Query</strong>.</li><li><strong>Store Local (Signals)</strong>: Quando o módulo precisa de estado local (filtros, seleção).</li><li><strong>Componentes (View Layer)</strong>: Standalone components com <code>ChangeDetectionStrategy.OnPush</code>.</li></ul><h2 id="_3-padroes-de-banco-de-dados" tabindex="-1">3. PADRÕES DE BANCO DE DADOS <a class="header-anchor" href="#_3-padroes-de-banco-de-dados" aria-label="Permalink to &quot;3. PADRÕES DE BANCO DE DADOS&quot;">​</a></h2><ul><li>Tabelas com UUIDs (<code>gen_random_uuid()</code>)</li><li><code>clinic_id</code> em todas as tabelas de negócio</li><li>RLS políticas para isolamento multi-tenant</li></ul><h2 id="_4-fluxo-git-e-kanban-do-codigo" tabindex="-1">4. FLUXO GIT E KANBAN DO CÓDIGO <a class="header-anchor" href="#_4-fluxo-git-e-kanban-do-codigo" aria-label="Permalink to &quot;4. FLUXO GIT E KANBAN DO CÓDIGO&quot;">​</a></h2><p>O NEXUS define o fluxo Git: <code>main (Cânon) ← draft (O Moinho) ← checkpoint/task-XXXX</code></p><h2 id="_5-plano-de-implementacao-kanban-visual" tabindex="-1">5. PLANO DE IMPLEMENTAÇÃO: KANBAN VISUAL <a class="header-anchor" href="#_5-plano-de-implementacao-kanban-visual" aria-label="Permalink to &quot;5. PLANO DE IMPLEMENTAÇÃO: KANBAN VISUAL&quot;">​</a></h2><p>Proponho a implementação de um módulo Kanban seguindo fielmente a arquitetura DDD + Signals + TanStack Query.</p><ul><li><code>modules/kanban/domain/models/kanban-board.model.ts</code></li><li><code>modules/kanban/application/store/kanban-board.store.ts</code> (Signals)</li><li><code>modules/kanban/application/services/kanban-card.service.ts</code> (TanStack Query)</li><li>Supabase Migrations (<code>YYYYMMDDHHMMSS_kanban.sql</code>) com RLS <code>USING (clinic_id = (SELECT selected_clinic_id()))</code>.</li></ul><h2 id="_6-sumario-dos-padroes-arquiteturais" tabindex="-1">6. SUMÁRIO DOS PADRÕES ARQUITETURAIS <a class="header-anchor" href="#_6-sumario-dos-padroes-arquiteturais" aria-label="Permalink to &quot;6. SUMÁRIO DOS PADRÕES ARQUITETURAIS&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspecto</th><th>Padrão</th></tr></thead><tbody><tr><td>Estrutura de módulo</td><td>DDD 3 camadas</td></tr><tr><td>Frameworks</td><td>Angular standalone + zoneless</td></tr><tr><td>Estado remoto</td><td>TanStack Query</td></tr><tr><td>Estado local</td><td>Angular Signals</td></tr><tr><td>Git workflow</td><td>Checkpoint → Draft → Main (ff-only)</td></tr></tbody></table>',18)])])}const g=e(r,[["render",d]]);export{p as __pageData,g as default};
